import { User, Order, Product } from './types';

export function validateData(data: { users: User[], orders: Order[], products: Product[] }): {
  isValid: boolean;
  issues: string[];
} {
  const issues: string[] = [];

  // Validate users
  data.users.forEach((user, index) => {
    if (!user.id.startsWith('user_')) {
      issues.push(`User ${index + 1} ID prefix invalid: ${user.id}`);
    }
    if (typeof user.timestamp !== 'number') {
      issues.push(`User ${index + 1} timestamp is not a number`);
    }
    if (typeof user.balanceCents !== 'number' || !Number.isInteger(user.balanceCents)) {
      issues.push(`User ${index + 1} balance is not an integer`);
    }
  });

  // Validate orders
  data.orders.forEach((order, index) => {
    if (!order.id.startsWith('order_')) {
      issues.push(`Order ${index + 1} ID prefix invalid: ${order.id}`);
    }
    if (typeof order.timestamp !== 'number') {
      issues.push(`Order ${index + 1} timestamp is not a number`);
    }
    if (typeof order.userId !== 'string') {
      issues.push(`Order ${index + 1} user ID is not a string`);
    }
    if (typeof order.productId !== 'string') {
      issues.push(`Order ${index + 1} product ID is not a string`);
    }
    if (typeof order.amountCents !== 'number' || !Number.isInteger(order.amountCents)) {
      issues.push(`Order ${index + 1} amount is not an integer`);
    }
  });

  // Validate products
  data.products.forEach((product, index) => {
    if (!product.id.startsWith('product_')) {
      issues.push(`Product ${index + 1} ID prefix invalid: ${product.id}`);
    }
    if (typeof product.timestamp !== 'number') {
      issues.push(`Product ${index + 1} timestamp is not a number`);
    }
    if (typeof product.name !== 'string') {
      issues.push(`Product ${index + 1} name is not a string`);
    }
    if (typeof product.priceCents !== 'number' || !Number.isInteger(product.priceCents)) {
      issues.push(`Product ${index + 1} price is not an integer`);
    }
  });

  return {
    isValid: issues.length === 0,
    issues
  };
}
