    data.orders.forEach(order => {
        if (!order.id.startsWith('order_') || !order.user_id.startsWith('user_')) {
            errors.push(`Invalid order or user ID format`);
        }
    });

    data.products.forEach(product => {
        if (!product.id.startsWith('product_')) {
            errors.push(`Invalid product ID format: ${product.id}`);
        }
    });

    // Validate monetary values
    data.orders.forEach(order => {
        if (order.total_cents < 0) {
            errors.push(`Negative order total cents: ${order.total_cents}`);
        }
    });

    data.products.forEach(product => {
        if (product.price_cents < 0 || product.price_cents % 100 !== 0) { // Must be divisible by 100
            errors.push(`Invalid price cents format for product: ${product.id} (${product.price_cents})`);
        }
    });

    // Validate timestamps
    data.users.forEach(user => {
        if (user.created_at < Date.now() - 86400000 || user.created_at > Date.now()) { // Must be within last day or future
            errors.push(`Invalid user creation timestamp: ${user.created_at}`);
        }
    });

    data.orders.forEach(order => {
        if (order.created_at < Date.now() - 604800000 || order.created_at > Date.now()) { // Within past week or future
            errors.push(`Invalid order creation timestamp: ${order.created_at}`);
        }
    });

    return errors;
}
