// validate.ts

import { User, Order, Product } from './types';
import { generateData } from './generate';

function isValidMonetaryValue(value?: number): value is number {
    return typeof value === 'number' && Number.isInteger(value);
}

function isValidTimestamp(timestamp: any): timestamp is { milliseconds: number } {
    return typeof timestamp.milliseconds === 'number';
}

function isValidEntityId(id: string, type: string): boolean {
    return id.startsWith(type) && id.length > 4;
}

function validateUsers(users: User[]): void {
    for (const user of users) {
        if (!isValidTimestamp(user.timestamp)) throw new Error(`Invalid timestamp for user ${user.id}`);
        if (!isValidEntityId(user.id, 'user_')) throw new Error(`Invalid ID for user ${user.id}`);
    }
}

function validateOrders(orders: Order[]): void {
    for (const order of orders) {
        if (!isValidTimestamp(order.timestamp)) throw new Error(`Invalid timestamp for order ${order.id}`);
        if (!isValidEntityId(order.userId, 'user_')) throw new Error(`Invalid user ID in order ${order.id}`);
        if (!['pending', 'shipped', 'delivered'].includes(order.status)) {
            throw new Error(`Invalid status "${order.status}" for order ${order.id}`);
        }
    }
}

function validateProducts(products: Product[]): void {
    for (const product of products) {
        if (!isValidTimestamp(product.timestamp)) throw new Error(`Invalid timestamp for product ${product.id}`);
        if (!isValidEntityId(product.id, 'product_')) throw new Error(`Invalid ID for product ${product.id}`);

        if (product.priceInCents !== undefined && !isValidMonetaryValue(product.priceInCents)) {
            throw new Error(`Invalid price in cents for product ${product.id}`);
        }
    }
}

export function validateData(users: User[], orders: Order[], products: Product[]): void {
    validateUsers(users);
    validateOrders(orders);
    validateProducts(products);
}
