const https = require('https');
const fs = require('fs');

// Function to fetch API data with error handling
function fetchPrices() {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: 'localhost',
      port: 34787,
      path: '/prices',
      method: 'GET'
    };

    const req = https.request(options, (res) => {
      let data = '';

      res.on('data', (chunk) => {
        data += chunk;
      });

      res.on('end', () => {
        try {
          resolve(JSON.parse(data));
        } catch (error) {
          reject(error);
        }
      });
    });

    req.on('error', (error) => {
      console.error(`Error fetching prices: ${error.message}`);
      reject(error);
    });

    req.end();
  });
}

// Function to write summary to prices.md
function writePriceSummary(prices, isFallback = false) {
  const today = new Date().toISOString().split('T')[0];
  const filename = 'prices.md';

  let content = `# Cryptocurrency Prices - ${today}\n\n`;

  // Write current price data
  Object.keys(prices).forEach(coin => {
    const priceData = prices[coin];

    content += `## ${coin} (${priceData.symbol})\n`;
    content += `- Current Price: $${priceData.currentPrice.toFixed(2)}\n`;
    content += `- 24h Change: ${priceData.change}%\n`;
    content += `- Market Cap: $${priceData.marketCap.toLocaleString()}\n\n`;

    // Check for errors in the fallback data
    if (isFallback && priceData.errors) {
      content += `### Error: Failed to fetch actual price data. Using fallback data.\n`;
      content += `- Current Price: $${priceData.currentPrice.toFixed(2)}\n`; // Fallback price
      content += `- 24h Change: ${priceData.change}% (Note: This is from the fallback file)\n`;
      content += `- Market Cap: $${priceData.marketCap.toLocaleString()}\n\n`;
    }
  });

  fs.writeFileSync(filename, content);

  console.log(`Price summary written to prices.md`);
}

